import pull from "../../../../../../../../../../../subject_repositories/pull-stream/pull.js"

describe("pull case 3 mutation detection via call count", () => {
  it("processes exactly 3 through functions, not 4, when partial applied with 3 args", () => {
    const callCounts = [0, 0, 0]

    const t1 = (read: Function) => { callCounts[0]++; return read }
    const t2 = (read: Function) => { callCounts[1]++; return read }
    const t3 = (read: Function) => { callCounts[2]++; return read }

    const pipeline = pull(t1, t2, t3)

    const source = (end: any, cb: Function) => cb(true)

    pipeline(source)

    // Each through should be called exactly once
    expect(callCounts).toEqual([1, 1, 1])
  })
})
